import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';


function MyBookings() {
  const navigate = useNavigate();
  const [bookings, setBookings] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  
  // Payment Modal State
  const [showPaymentModal, setShowPaymentModal] = useState(false);
  const [selectedBooking, setSelectedBooking] = useState(null);
  const [paymentMethod, setPaymentMethod] = useState('card');
  const [paymentLoading, setPaymentLoading] = useState(false);

  useEffect(() => {
    fetchBookings();
  }, []);

  const fetchBookings = async () => {
    try {
      const token = localStorage.getItem('token');
      const response = await axios.get('http://localhost:5000/api/bookings/my', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setBookings(response.data.bookings);
    } catch (err) {
      setError('Failed to load bookings');
    } finally {
      setLoading(false);
    }
  };

  const handleCancelBooking = async (bookingId) => {
    if (!window.confirm('Are you sure you want to cancel this booking?')) {
      return;
    }

    try {
      const token = localStorage.getItem('token');
      await axios.put(
        `http://localhost:5000/api/bookings/${bookingId}/cancel`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );

      alert('Booking cancelled successfully!');
      fetchBookings();
    } catch (err) {
      alert('Failed to cancel booking');
    }
  };

  const openPaymentModal = (booking) => {
    setSelectedBooking(booking);
    setShowPaymentModal(true);
  };

  const closePaymentModal = () => {
    setShowPaymentModal(false);
    setSelectedBooking(null);
    setPaymentMethod('card');
  };

  const handlePayment = async () => {
    setPaymentLoading(true);
    setError('');

    try {
      const token = localStorage.getItem('token');
      await axios.post(
        'http://localhost:5000/api/payments',
        {
          bookingId: selectedBooking._id,
          paymentMethod
        },
        { headers: { Authorization: `Bearer ${token}` } }
      );

      alert('Payment successful! 🎉');
      closePaymentModal();
      fetchBookings();
    } catch (err) {
      setError(err.response?.data?.message || 'Payment failed');
    } finally {
      setPaymentLoading(false);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'confirmed': return 'bg-green-100 text-green-800';
      case 'pending': return 'bg-yellow-100 text-yellow-800';
      case 'cancelled': return 'bg-red-100 text-red-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  const getPaymentStatusColor = (status) => {
    switch (status) {
      case 'paid': return 'bg-green-100 text-green-800';
      case 'unpaid': return 'bg-red-100 text-red-800';
      case 'refunded': return 'bg-blue-100 text-blue-800';
      default: return 'bg-gray-100 text-gray-800';
    }
  };

  if (loading) {
    return (
      <div>
        <Navbar />
        <div className="container mx-auto px-4 py-20 text-center">
          <div className="text-2xl">Loading bookings...</div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gray-50">
      <Navbar />

      {/* Header */}
      <div className="bg-gradient-to-r from-blue-600 to-purple-600 py-8">
        <div className="container mx-auto px-4">
          <h1 className="text-4xl font-bold text-white">My Bookings</h1>
          <p className="text-white/90 mt-2">View and manage your event bookings</p>
        </div>
      </div>

      <div className="container mx-auto px-4 py-8">
        {error && (
          <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mb-4">
            {error}
          </div>
        )}

        {bookings.length === 0 ? (
          <div className="bg-white rounded-2xl shadow-lg p-12 text-center">
            <div className="text-6xl mb-4">🎫</div>
            <h2 className="text-2xl font-bold text-gray-800 mb-2">No bookings yet</h2>
            <p className="text-gray-600 mb-6">Start booking amazing events!</p>
            <button
              onClick={() => navigate('/events')}
              className="bg-blue-600 text-white px-8 py-3 rounded-lg hover:bg-blue-700 transition font-semibold"
            >
              Browse Events
            </button>
          </div>
        ) : (
          <div className="space-y-6">
            {bookings.map((booking) => (
              <div key={booking._id} className="bg-white rounded-2xl shadow-lg overflow-hidden hover:shadow-xl transition">
                <div className="grid md:grid-cols-4 gap-6 p-6">
                  
                  {/* Event Image */}
                  <div>
                    <img
                      src={booking.event?.image || 'https://via.placeholder.com/300x200?text=Event'}
                      alt={booking.event?.name}
                      className="w-full h-32 object-cover rounded-lg"
                    />
                  </div>

                  {/* Event Details */}
                  <div className="md:col-span-2">
                    <h3 className="text-2xl font-bold mb-3">{booking.event?.name}</h3>
                    
                    <div className="space-y-2 text-gray-600">
                      <div className="flex items-center">
                        <span className="mr-2">📅</span>
                        <span>
                          {new Date(booking.event?.date).toLocaleDateString()} at {booking.event?.time}
                        </span>
                      </div>
                      
                      <div className="flex items-center">
                        <span className="mr-2">📍</span>
                        <span>{booking.event?.venue}</span>
                      </div>
                      
                      <div className="flex items-center">
                        <span className="mr-2">🎫</span>
                        <span>{booking.numberOfTickets} ticket(s)</span>
                      </div>
                      
                      <div className="flex items-center">
                        <span className="mr-2">💰</span>
                        <span className="font-bold text-xl text-blue-600">₹{booking.totalAmount}</span>
                      </div>
                    </div>

                    {/* Status Badges */}
                    <div className="flex gap-2 mt-4">
                      <span className={`px-3 py-1 rounded-full text-xs font-semibold ${getStatusColor(booking.status)}`}>
                        {booking.status.toUpperCase()}
                      </span>
                      <span className={`px-3 py-1 rounded-full text-xs font-semibold ${getPaymentStatusColor(booking.paymentStatus)}`}>
                        {booking.paymentStatus.toUpperCase()}
                      </span>
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="flex flex-col justify-center gap-3">
                    {booking.paymentStatus === 'unpaid' && booking.status !== 'cancelled' && (
                      <button
                        onClick={() => openPaymentModal(booking)}
                        className="bg-green-600 text-white px-6 py-3 rounded-lg hover:bg-green-700 font-semibold transition"
                      >
                        Pay Now
                      </button>
                    )}

                    {booking.status !== 'cancelled' && (
                      <button
                        onClick={() => handleCancelBooking(booking._id)}
                        className="bg-red-600 text-white px-6 py-3 rounded-lg hover:bg-red-700 font-semibold transition"
                      >
                        Cancel Booking
                      </button>
                    )}

                    <div className="text-xs text-gray-500 text-center mt-2">
                      Booked: {new Date(booking.bookingDate).toLocaleDateString()}
                    </div>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* Payment Modal */}
      {showPaymentModal && selectedBooking && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-2xl max-w-md w-full p-8 max-h-screen overflow-y-auto">
            
            {/* Header */}
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold">Complete Payment</h2>
              <button
                onClick={closePaymentModal}
                className="text-gray-500 hover:text-gray-700 text-3xl leading-none"
              >
                ×
              </button>
            </div>

            {/* Booking Summary */}
            <div className="bg-gray-50 rounded-lg p-4 mb-6">
              <h3 className="font-bold mb-3">Booking Summary</h3>
              <div className="space-y-2 text-sm">
                <div className="flex justify-between">
                  <span className="text-gray-600">Event:</span>
                  <span className="font-semibold">{selectedBooking.event?.name}</span>
                </div>
                <div className="flex justify-between">
                  <span className="text-gray-600">Tickets:</span>
                  <span className="font-semibold">{selectedBooking.numberOfTickets}</span>
                </div>
                <div className="flex justify-between text-lg font-bold mt-3 pt-3 border-t">
                  <span>Total:</span>
                  <span className="text-blue-600">₹{selectedBooking.totalAmount}</span>
                </div>
              </div>
            </div>

            {/* Payment Methods */}
            <div className="mb-6">
              <h3 className="font-bold mb-4">Payment Method</h3>
              
              {error && (
                <div className="bg-red-100 border border-red-400 text-red-700 px-4 py-3 rounded mb-4 text-sm">
                  {error}
                </div>
              )}

              <div className="space-y-3">
                {['card', 'upi', 'netbanking', 'wallet'].map((method) => (
                  <label
                    key={method}
                    className="flex items-center p-4 border-2 rounded-lg cursor-pointer hover:bg-gray-50 transition"
                    style={{ borderColor: paymentMethod === method ? '#3B82F6' : '#E5E7EB' }}
                  >
                    <input
                      type="radio"
                      name="payment"
                      value={method}
                      checked={paymentMethod === method}
                      onChange={(e) => setPaymentMethod(e.target.value)}
                      className="mr-3"
                    />
                    <span className="text-xl mr-3">
                      {method === 'card' ? '💳' : method === 'upi' ? '📱' : method === 'netbanking' ? '🏦' : '👛'}
                    </span>
                    <span className="font-semibold capitalize">{method === 'netbanking' ? 'Net Banking' : method}</span>
                  </label>
                ))}
              </div>
            </div>

            {/* Action Buttons */}
            <div className="flex gap-3">
              <button
                onClick={closePaymentModal}
                className="flex-1 bg-gray-200 text-gray-700 py-3 rounded-lg font-semibold hover:bg-gray-300 transition"
              >
                Cancel
              </button>
              <button
                onClick={handlePayment}
                disabled={paymentLoading}
                className="flex-1 bg-green-600 text-white py-3 rounded-lg font-semibold hover:bg-green-700 transition disabled:opacity-50"
              >
                {paymentLoading ? 'Processing...' : `Pay ₹${selectedBooking.totalAmount}`}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default MyBookings;
